+    #[test]
+    fn test_prepared_query_row_row_cap_path_counts_successful_execution() {
+        let dir = tempfile::tempdir().unwrap();
+        let db_path = dir.path().join("prepared-query-row-row-cap-stats.db");
+        let db_path = db_path.to_string_lossy().into_owned();
+
+        let conn = Connection::open(&db_path).unwrap();
+        conn.execute("CREATE TABLE prep_query_row_row_cap (id INTEGER PRIMARY KEY, val TEXT);")
+            .unwrap();
+        conn.execute("INSERT INTO prep_query_row_row_cap VALUES (1, 'alpha'), (2, 'beta');")
+            .unwrap();
+
+        let stmt = conn
+            .prepare("SELECT COUNT(*) FROM prep_query_row_row_cap WHERE id > 0;")
+            .unwrap();
+        assert!(
+            stmt.prepared_query_fast_path.is_none(),
+            "filtered COUNT(*) should stay on the generic prepared query_row path",
+        );
+        assert!(
+            stmt.can_use_query_row_result_row_cap(),
+            "filtered COUNT(*) should still qualify for the row-cap query_row executor",
+        );
+
+        let before = conn.query("PRAGMA fsqlite.connection_stats;").unwrap();
+        let before_total = connection_stat_metric(&before, "queries_executed_total");
+        let before_current = connection_stat_metric(&before, "current_connection_queries_executed");
+
+        let row = stmt.query_row().unwrap();
+        assert_eq!(row.values, vec![SqliteValue::Integer(2)]);
+
+        let after = conn.query("PRAGMA fsqlite.connection_stats;").unwrap();
+        let after_total = connection_stat_metric(&after, "queries_executed_total");
+        let after_current = connection_stat_metric(&after, "current_connection_queries_executed");
+
+        assert_eq!(
+            after_total.saturating_sub(before_total),
+            2,
+            "prepared query_row row-cap path should count the query itself plus the stats PRAGMA",
+        );
+        assert_eq!(
+            after_current.saturating_sub(before_current),
+            2,
+            "per-connection query counts should include successful row-cap query_row executions",
+        );
